+                    // Skip script path with H internal key
+                    return std::nullopt;
+                }
+            }
+        }
+
+        pubkey = XOnlyPubKey{solutions[0]};
+    } else if (type == TxoutType::WITNESS_V0_KEYHASH && !txin.scriptWitness.stack.empty()) {
